scwin.gr_415List_oncellclick = async function (rowIndex, columnIndex, columnId) {
  ds_415List.getRowStatus(rowIndex);
  //변경한 데이터가 있는지 체크한다. 
  if (ds_415List.getRowStatus(rowIndex) == "U" || ds_451List.getRowStatus(rowIndex) == "U") {
    let confirmResult = await $c.win.confirm($p, scwin.MSG_CM_CRM_002);
    if (confirmResult) {
      //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
      for (var i = 0; i < ds_415List.getRowCount(); i++) {
        var rowJson = ds_415List.getRowJSON(i);
        if (ds_415List.rowStatus == "C" || ds_415List.rowStatus == "U") {
          if (rowJson.privGrpId.trim() == '') {
            $c.win.alert($p, scwin.MSG_CM_ERR_001);
            return;
          } else if (rowJson.privGrpId.trim().length != 4) {
            $c.win.alert($p, scwin.MSG_CM_ERR_002);
            return;
          } else if (rowJson.privGrpNm.trim() == '') {
            $c.win.alert($p, scwin.MSG_CM_ERR_003);
            return;
          }
          for (var j = 0; j < ds_415List.getRowCount(); j++) {
            if (j != i) {
              if (rowJson.privGrpId.trim() == ds_415List.getCellData(j, "privGrpId").trim()) {
                $c.win.alert($p, scwin.MSG_CM_ERR_004);
                return;
              }
            }
          }
        }
      }
      $c.sbm.execute($p, sbm_save);
    }
  }
  if (ds_415List.getRowStatus(rowIndex) == "C") {
    gr_415List.setReadOnly("column", "privGrpId", false);
  } else {
    gr_415List.setReadOnly("column", "privGrpId", true);
    scwin.f_MainRetrieve(gr_415List.getCellData(rowIndex, "privGrpId"));
  }
};
