scwin.f_Filter = function () {
  var pgmCond = lc_pgmCond.getValue();
  var pgmName = ed_pgmName.getValue();
  var rcolumnId = "pgmId";
  switch (pgmCond) {
    case "1":
      rcolumnId = "pgmId";
      break;
    case "2":
      rcolumnId = "pgmNm";
      break;
  }
  if (pgmCond > 0) {
    $c.data.dataListFilter($p, ds_451List, "LIKE", true, {
      colId: rcolumnId,
      func: function (cellData, tmpParam, rowIdx) {
        if (cellData.indexOf(pgmName) > -1) {
          return true;
        }
        return false; // return이 true인 경우 적용하고 false인 경우 넘김
      }
    });
  } else {
    ds_451List.removeColumnFilterAll();
  }
};
